// The loaded wavetables (uzu-wavetables map). Same deal for the wt_ prefix.
export const WT_SOUNDS = new Set(["wt_digital", "wt_digital_bad_day", "wt_digital_basique", "wt_digital_crickets", "wt_digital_curses", "wt_digital_echoes", "wt_vgame"]);

/** Is `name` a real MELODIC sound the player can load — an oscillator / palette sample, a GM
 *  soundfont, or a wavetable? (Strips a trailing `:sampleIndex`.) The single validity test for
 *  model-suggested sounds: a name NOT here loads NOTHING and throws "sound … not found" the moment
 *  it plays — so the compose binder, the enrich swap options, and the UI all gate on it. */
export const isKnownSound = (name: string): boolean => {
  const base = (name || "").split(":")[0];
  return PALETTE_SOUNDS.has(base) || GM_SOUNDS.has(base) || WT_SOUNDS.has(base);
};

/** Is `name` a real drum-machine bank for `.bank("…")`? */
export const isKnownBank = (name: string): boolean => PALETTE_BANKS.has(name || "");
